// ─── Step indicator ───────────────────────────────────────────────────────────
const steps = ["Velkomst","Grund","Græs","Bede","Træer","Stil","Tilvalg","Din plan"];

const Stepper = ({ current }) => (
  <div className="flex items-center justify-center gap-0 overflow-x-auto py-2 px-4">
    {steps.map((s, i) => (
      <div key={i} className="flex items-center">
        <div className={`flex flex-col items-center ${i <= current ? "opacity-100" : "opacity-40"}`}>
          <div className={`w-7 h-7 rounded-full flex items-center justify-center text-xs font-bold border-2 transition-all duration-300
            ${i < current ? "bg-green-700 border-green-700 text-white" :
              i === current ? "bg-amber-50 border-green-700 text-green-800" :
              "bg-white border-stone-300 text-stone-400"}`}>
            {i < current ? <CheckIcon/> : i + 1}
          </div>
          <span className={`text-xs mt-1 hidden sm:block whitespace-nowrap ${i === current ? "text-green-800 font-semibold" : "text-stone-400"}`}>
            {s}
          </span>
        </div>
        {i < steps.length - 1 && (
          <div className={`w-6 sm:w-10 h-0.5 mb-4 mx-0.5 transition-all duration-300 ${i < current ? "bg-green-700" : "bg-stone-200"}`}/>
        )}
      </div>
    ))}
  </div>
);

