// ─── Number input ─────────────────────────────────────────────────────────────
const NumInput = ({ value, onChange, label, suffix = "m²", min = 0 }) => (
  <div className="mt-3">
    <label className="text-xs text-stone-500 mb-1 block">{label}</label>
    <div className="flex items-center gap-2">
      <div className="flex items-center border-2 border-stone-200 rounded-xl overflow-hidden w-36">
        <button onClick={() => onChange(Math.max(min, (value||0) - 1))}
          className="px-3 py-2 bg-stone-50 text-stone-500 hover:bg-stone-100 text-lg font-bold">−</button>
        <input type="number" value={value||""} min={min}
          onChange={e => onChange(parseFloat(e.target.value)||0)}
          className="w-full text-center py-2 text-sm font-semibold text-stone-800 outline-none bg-white"/>
        <button onClick={() => onChange((value||0) + 1)}
          className="px-3 py-2 bg-stone-50 text-stone-500 hover:bg-stone-100 text-lg font-bold">+</button>
      </div>
      <span className="text-xs text-stone-400">{suffix}</span>
    </div>
  </div>
);

